module top_module (
	input clk,
	input reset,
	input enable,
	output reg [3:0] count);

always @(posedge clk or posedge reset) begin
	if (reset)
		count <= 4'b0000;
	else if (enable)
		count <= count + 1;
end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        count <= 4'b1111;
      end else if (!enable) begin
        count <= count - 1;
      end
    end
  end

endmodule

